function syncSegmentsToBudget(trip) {
    (trip.accommodation || []).forEach(acc => {
        const isBooked = acc.status === 'booked';
        const expense = (trip.budget?.expenses || []).find(e => e.sourceId === acc.id && e.sourceType === 'accommodation');
        if (expense && isBooked) {
            expense.paymentStatus = 'pre_paid';
            expense.status = 'confirmed';
            expense.paymentMethod = expense.paymentMethod || 'credit_card';
        }
    });
    (trip.flights || []).forEach(flight => {
        const isBooked = flight.isBooked;
        const expense = (trip.budget?.expenses || []).find(e => e.sourceId === flight.id && e.sourceType === 'flight');
        if (expense && isBooked) {
            expense.paymentStatus = 'pre_paid';
            expense.status = 'confirmed';
            expense.paymentMethod = expense.paymentMethod || 'credit_card';
        }
    });
}
